@namespace Lumeo
@implements IAsyncDisposable

@* ChildContent renders declarative annotations (ChartThreshold, ChartReferenceZone).
   Wrapped in a hidden CascadingValue so the children themselves emit no DOM — they just
   register their config via the cascaded ChartAnnotationsContext. The chart picks up
   the registrations in GetOptionsJson and merges them into series[0].markLine /
   markArea, without mutating the consumer-passed EChartOption. *@
<CascadingValue Value="_annotations" IsFixed="true">
    <CascadingValue Value="_tooltipRegistration" IsFixed="true">
        @ChildContent
    </CascadingValue>
</CascadingValue>

@* Hidden DOM portal for the optional ChartTooltip slot. ECharts owns the visible
   tooltip element; we render the consumer's Razor markup into this off-screen div
   and the JS-side formatter (registered via registerTooltipSlot) returns
   portal.innerHTML each frame. The portal stays mounted as long as a ChartTooltip
   is registered so ECharts' formatter never returns an empty string after the
   first hover. *@
@if (_tooltipRegistration.Current is { } slot)
{
    <div id="@_tooltipPortalId" class="@($"lumeo-chart-tooltip-portal {slot.Class}".Trim())"
         style="display:none" @attributes="slot.AdditionalAttributes">
        @slot.ChildContent(_tooltipContext)
    </div>
}

@if (_initError is not null)
{
    <div class="@($"flex items-center justify-center text-sm text-destructive border border-destructive/30 rounded-md bg-destructive/5 {Class}".Trim())" style="@StyleStr" @attributes="AdditionalAttributes">
        <span>@_initError</span>
    </div>
}
else
{
    <div class="@RootCssClass" style="@RootStyleStr" @attributes="AdditionalAttributes">
        <div id="@_chartId" class="lumeo-chart-host w-full h-full"
             role="@(string.IsNullOrEmpty(HostAriaLabel) ? null : "img")" aria-label="@HostAriaLabel"
             tabindex="@HostTabIndex"
             style="@HostStyle"></div>
        @if (AccessibilityLayer && _a11yTable is { } _table)
        {
            @* Screen-reader accessibility layer (shadcn `accessibilityLayer` parity for
               canvas). ECharts paints to <canvas>, which is opaque to assistive tech, so
               we project the series data into a visually-hidden but SR-navigable table.
               The focusable host above carries the summary as its aria-label. *@
            <table class="sr-only" aria-label="@_table.Summary">
                <caption>@_table.Summary</caption>
                <thead>
                    <tr>
                        @foreach (var header in _table.ColumnHeaders)
                        {
                            <th scope="col">@header</th>
                        }
                    </tr>
                </thead>
                <tbody>
                    @foreach (var row in _table.Rows)
                    {
                        <tr>
                            <th scope="row">@row.Header</th>
                            @foreach (var cell in row.Cells)
                            {
                                <td>@cell</td>
                            }
                        </tr>
                    }
                    @* Overflow marker when the row cap truncated a big series — one
                       spanning row announcing the omitted count. The caption above
                       still carries the true total. *@
                    @if (_table.TruncationNote is { } truncationNote)
                    {
                        <tr>
                            <td colspan="@_table.ColumnHeaders.Count">@truncationNote</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        @if (ShouldShowSkeleton && SkeletonStyle == ChartSkeletonStyle.Silhouette)
        {
            @* Silhouette mode (legacy SVG skeleton overlay). Phantom mode renders the real
               ECharts with placeholder data instead — no DOM element needed here. *@
            <div style="position: absolute; inset: 0; pointer-events: none;">
                <ChartSkeleton Kind="@SkeletonKind" Width="100%" Height="100%" Class="!rounded-none" />
            </div>
        }
        @if (ShouldShowSkeleton && ShowLoadingLabel)
        {
            @* Loading label — small top-right pill (spinner + text) overlaid on TOP of
               whichever skeleton style is active. Tells users explicitly "this is loading"
               so the cycling phantom data isn't mistaken for a bug. Doesn't block the
               chart underneath (small, corner-aligned). Disable via ShowLoadingLabel=false
               for bare phantom/silhouette visuals. *@
            <div role="status" aria-live="polite" aria-label="@(LoadingText ?? L["Chart.Loading"])"
                 class="absolute top-2 right-2 flex items-center gap-1.5 rounded-[calc(var(--radius)*2)] border border-border/60 bg-background/85 backdrop-blur-sm px-2.5 py-1 shadow-sm pointer-events-none">
                <SvgGlyph Svg="@(LumeoIcons.LoaderCircle)" class="h-3.5 w-3.5 text-muted-foreground animate-spin" />
                @{
                    var _chartLoadingLabel = LoadingText ?? L["Chart.Loading"];
                }
                @if (!string.IsNullOrEmpty(_chartLoadingLabel))
                {
                    <span class="text-xs font-medium text-muted-foreground">@_chartLoadingLabel</span>
                }
            </div>
        }
    </div>
}

@inject ComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    /// <summary>Typed ECharts option to render. Ignored when <see cref="OptionJson"/> is set.</summary>
    [Parameter] public EChartOption? Option { get; set; }
    /// <summary>Raw ECharts option as a JSON string, used instead of <see cref="Option"/> when set — an escape hatch for option shapes not covered by the typed model.</summary>
    [Parameter] public string? OptionJson { get; set; }
    /// <summary>Declarative children — <see cref="ChartThreshold"/> and
    /// <see cref="ChartReferenceZone"/>. Other content renders nothing visible.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>ECharts theme name (or registered custom theme) applied on init; changing it disposes and reinitializes the underlying chart instance.</summary>
    [Parameter] public string? Theme { get; set; }
    /// <summary>URL of the ECharts UMD bundle to load. Falls back to the library-bundled version when not set.</summary>
    [Parameter] public string? EChartsSource { get; set; }
    /// <summary>Accessible text alternative for the chart (WCAG 1.1.1). When set, the
    /// canvas host is exposed as <c>role="img"</c> with this <c>aria-label</c> so screen
    /// readers announce a summary instead of an empty graphic. Strongly recommended.</summary>
    [Parameter] public string? AriaLabel { get; set; }
    /// <summary>When <c>true</c> (default, matching shadcn's <c>accessibilityLayer</c>),
    /// the chart renders a visually-hidden data table built from the series data and
    /// makes the canvas host keyboard-focusable with a summarising <c>aria-label</c>, so
    /// screen-reader and keyboard users can reach the otherwise opaque <c>&lt;canvas&gt;</c>
    /// data. When <see cref="AriaLabel"/> is not set, a generated summary of the data is
    /// used as the label. Set to <c>false</c> to opt out entirely.</summary>
    [Parameter] public bool AccessibilityLayer { get; set; } = true;
    /// <summary>Upper bound on the number of data rows the hidden screen-reader table
    /// materialises (default <see cref="ChartAccessibility.DefaultMaxAccessibilityRows"/>).
    /// A big series would otherwise emit one hidden <c>&lt;tr&gt;</c> per data point —
    /// thousands of rows of DOM bloat that no assistive tech can usefully navigate.
    /// Above the cap the table keeps the first N rows plus a single "… and N more data
    /// points" row; the host's summarising <c>aria-label</c> is built from the FULL data
    /// so its totals stay accurate. Set to <c>0</c> (or negative) to disable the cap and
    /// render every row.</summary>
    [Parameter] public int MaxAccessibilityRows { get; set; } = ChartAccessibility.DefaultMaxAccessibilityRows;
    /// <summary>CSS width of the chart container. Defaults to <c>100%</c>.</summary>
    [Parameter] public string Width { get; set; } = "100%";
    /// <summary>CSS height of the chart container. Defaults to <c>350px</c>.</summary>
    [Parameter] public string Height { get; set; } = "350px";
    /// <summary>Invoked with the ECharts click-event payload when the user clicks a chart element.</summary>
    [Parameter] public EventCallback<ChartEventArgs> OnClick { get; set; }
    /// <summary>Invoked with the ECharts mouseover-event payload when the pointer hovers a chart element.</summary>
    [Parameter] public EventCallback<ChartEventArgs> OnMouseOver { get; set; }
    /// <summary>When true, shows ECharts' built-in loading spinner overlay — distinct from the skeleton driven by <see cref="IsLoading"/>.</summary>
    [Parameter] public bool ShowLoading { get; set; }
    /// <summary>Chart group name used to sync cursor/zoom interactions across multiple charts sharing the same group.</summary>
    [Parameter] public string? Group { get; set; }
    /// <summary>CSS <c>aspect-ratio</c> applied to the container instead of a fixed <see cref="Height"/> (e.g. <c>16/9</c>).</summary>
    [Parameter] public string? AspectRatio { get; set; }
    /// <summary>Invoked with the ECharts event payload when the user double-clicks a chart element.</summary>
    [Parameter] public EventCallback<ChartEventArgs> OnDoubleClick { get; set; }
    /// <summary>Invoked with the ECharts event payload when the user completes a brush selection.</summary>
    [Parameter] public EventCallback<ChartEventArgs> OnBrushSelected { get; set; }
    /// <summary>Invoked with the ECharts event payload when the user zooms or pans via data zoom.</summary>
    [Parameter] public EventCallback<ChartEventArgs> OnDataZoom { get; set; }
    /// <summary>Invoked with the error message when ECharts fails to initialize (e.g. an invalid <see cref="EChartsSource"/>).</summary>
    [Parameter] public EventCallback<string> OnInitError { get; set; }
    /// <summary>Additional CSS class(es) applied to the chart's root element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Additional HTML attributes captured and forwarded to the chart's root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    /// <summary>When true, forces the loading state on top of the chart
    /// (consumer is refetching data). Independent of the JS-driven ECharts loading
    /// indicator controlled by <see cref="ShowLoading"/>.</summary>
    [Parameter] public bool IsLoading { get; set; }
    /// <summary>When true (default), renders the loading state while the chart
    /// has not yet rendered for the first time, and whenever <see cref="IsLoading"/>
    /// is true. Set to <c>false</c> to opt out entirely.</summary>
    [Parameter] public bool ShowLoadingSkeleton { get; set; } = true;
    /// <summary>Shape family for the skeleton. Each chart wrapper presets a sensible
    /// default (bars for Bar, pie ring for Pie, etc.) — consumers only override when
    /// they want a different silhouette.</summary>
    [Parameter] public ChartSkeletonKind SkeletonKind { get; set; } = ChartSkeletonKind.Generic;
    /// <summary>Phantom (default) renders the real chart with synthesized placeholder
    /// data in a muted palette; ECharts animates the option swap to real data.
    /// Silhouette falls back to the legacy SVG overlay skeleton.</summary>
    [Parameter] public ChartSkeletonStyle SkeletonStyle { get; set; } = ChartSkeletonStyle.Phantom;
    /// <summary>Phantom-mode refresh interval in milliseconds — each tick regenerates
    /// the placeholder dataset with a new random seed so bars/lines/slices visibly
    /// redistribute while loading. Defaults to 1400ms; clamped to ≥200ms.</summary>
    [Parameter] public int PhantomCycleMs { get; set; } = 1400;
    /// <summary>Explicit override for the phantom layout (category count, series count,
    /// stacking, area fill). When null (default), the shape is inferred from the real
    /// <see cref="Option"/> so the phantom mirrors the actual chart structure.</summary>
    [Parameter] public PhantomShape? PhantomShapeOverride { get; set; }
    /// <summary>When true (default), overlays a small top-right pill containing a
    /// spinner and <see cref="LoadingText"/> on top of the active skeleton — a clear,
    /// always-on visual cue that the chart is loading. The pill renders independently
    /// of <see cref="SkeletonStyle"/> so phantom and silhouette both get the same
    /// hint. Set to <c>false</c> for bare visuals where the skeleton speaks for
    /// itself.</summary>
    [Parameter] public bool ShowLoadingLabel { get; set; } = true;
    /// <summary>Label rendered next to the spinner inside the loading pill. Set to
    /// <c>null</c> or empty to hide the text and show only the spinner. When not set,
    /// uses the active locale's "Chart.Loading" string (default: "Loading…").</summary>
    [Parameter] public string? LoadingText { get; set; }

    private readonly string _chartId = $"lumeo-chart-{Guid.NewGuid():N}";
    // Cascaded to <ChartThreshold> and <ChartReferenceZone> children. They register
    // their config here on OnParametersSet; GetOptionsJson merges the registrations
    // into the option JSON before handing it to ECharts. On change we re-emit the
    // updated JSON via OnAfterRenderAsync's existing _lastJson diff path.
    private readonly ChartAnnotationsContext _annotations;

    // Cascaded to <ChartTooltip>. When a slot is registered, we render the consumer's
    // RenderFragment into a hidden DOM portal whose innerHTML the JS-side tooltip
    // formatter returns each frame.
    private readonly ChartTooltipSlotRegistration _tooltipRegistration;
    private string _tooltipPortalId => $"{_chartId}-tooltip";
    private ChartTooltipContext _tooltipContext = ChartTooltipContext.Empty;
    private bool _tooltipBridgeRegistered;
    // Names of ECharts events already attached on the CURRENT live JS instance. The JS
    // registerChartEvent does NOT de-dupe — it pushes onto chart._lumeoEvents and
    // re-attaches each call — so we must track what's bound and only attach newly-added
    // ones. Cleared when the JS instance is disposed+reinit'd (theme change) since the
    // fresh chart has no listeners. Lets us safely re-run RegisterChartEventsAsync when a
    // delegate (OnClick/OnDataZoom/…) or the ChartTooltip slot appears AFTER first render.
    private readonly HashSet<string> _registeredEvents = new(StringComparer.Ordinal);

    public Chart()
    {
        _annotations = new ChartAnnotationsContext(onChanged: () => InvokeAsync(StateHasChanged));
        _tooltipRegistration = new ChartTooltipSlotRegistration(onChanged: () => InvokeAsync(StateHasChanged));
    }
    private IJSObjectReference? _module;
    private DotNetObjectReference<Chart>? _selfRef;
    private bool _initialized;
    private string? _lastJson;
    private bool _lastShowLoading;
    private string? _lastTheme;
    private string? _lastGroup;
    private string? _initError;
    // Structural fingerprint of the option that ECharts is currently showing — the
    // series count plus each series' data length and its markLine/markArea entry
    // counts. setOption(notMerge:false) merges component arrays by index, so when the
    // consumer REMOVES a series / data point / annotation the dropped tail-end items
    // would survive as ghosts. We compare the incoming fingerprint against this one and,
    // on any shrink, pass replaceMerge for the shrunk components so the removals stick.
    private ChartShape _lastShape = ChartShape.Empty;

    // Component types we ask ECharts to fully replace (rather than index-merge) when the
    // corresponding part of the option structurally shrinks. axis entries are listed so a
    // removed category axis doesn't linger; markLine/markArea cover removed annotations.
    private const string SeriesShrinkReplaceMergeJson =
        "[\"series\",\"xAxis\",\"yAxis\",\"radar\",\"angleAxis\",\"radiusAxis\"]";

    private string CssClass => $"{Class}".Trim();
    private string StyleStr => AspectRatio is not null
        ? $"width: {Width}; aspect-ratio: {AspectRatio};"
        : $"width: {Width}; height: {Height};";

    private string RootCssClass => $"relative {Class}".Trim();
    private string RootStyleStr => $"position: relative; {StyleStr}";

    // Screen-reader data table projected from the REAL option (never the phantom
    // placeholder), rebuilt in OnParametersSet whenever the option changes. Null when
    // there is no usable series data or the accessibility layer is disabled.
    private ChartAccessibility.ChartDataTable? _a11yTable;

    // The host's aria-label: the consumer-supplied AriaLabel wins; otherwise, when the
    // accessibility layer is on, fall back to the generated data summary so a chart with
    // no explicit label is still announced.
    private string? HostAriaLabel =>
        !string.IsNullOrEmpty(AriaLabel) ? AriaLabel
        : AccessibilityLayer ? _a11yTable?.Summary
        : null;

    // Make the canvas host reachable by keyboard (Tab) only when it actually announces
    // something — avoids adding an empty focus stop to charts with no label/data.
    private string? HostTabIndex =>
        AccessibilityLayer && !string.IsNullOrEmpty(HostAriaLabel) ? "0" : null;

    /// <summary>True when we should be showing a loading state. Keyed strictly on
    /// <c>IsLoading</c> — we do NOT show phantom/silhouette on initial mount, because
    /// ECharts initializes synchronously and a ready chart should render its real data
    /// on first paint. The loading state is reserved for explicit consumer refetches.</summary>
    private bool ShouldShowSkeleton => ShowLoadingSkeleton && IsLoading;

    // Silhouette mode hides the real chart while the SVG overlay takes its place.
    // Phantom mode keeps the chart host fully visible — the "skeleton" IS the chart
    // with placeholder data. To give phantom a "loading" look without polluting the
    // option.color palette (which would bleed through the merge into the real chart),
    // we apply a CSS grayscale+dim filter while phantom is active. The filter cleanly
    // transitions off when real data arrives — bars keep their real hue throughout.
    private string ChartHostOpacity => (ShouldShowSkeleton && SkeletonStyle == ChartSkeletonStyle.Silhouette) ? "0" : "1";

    private bool IsPhantomStyled =>
        ShouldShowSkeleton && SkeletonStyle == ChartSkeletonStyle.Phantom && ShowLoadingSkeleton;

    private string HostStyle => IsPhantomStyled
        ? $"transition: opacity 350ms ease-out, filter 500ms ease-out; opacity: {ChartHostOpacity}; filter: grayscale(0.85) saturate(0.15) opacity(0.78);"
        : $"transition: opacity 350ms ease-out, filter 500ms ease-out; opacity: {ChartHostOpacity}; filter: none;";

    // Phantom-mode state: cycling random placeholder data while loading, then one
    // clean "notMerge=true" swap to real data so the muted palette doesn't bleed.
    // Driven by a CancellationTokenSource + PeriodicTimer loop (replaces the older
    // System.Threading.Timer) so DisposeAsync can deterministically cancel and
    // await any in-flight callback before returning.
    private CancellationTokenSource? _phantomCts;
    private Task? _phantomLoopTask;
    private int _phantomTick;
    private bool _lastWasPhantom;
    private int _activePhantomCycleMs;
    private volatile bool _disposed;
    private int EffectivePhantomCycleMs => Math.Max(200, PhantomCycleMs);

    // Components whose phantom styling (muted palette, transparent text, skeleton-box
    // labels) must be wiped during the phantom↔real transition — otherwise they'd
    // persist under setOption merge semantics and bleed into the real chart.
    private const string PhantomTransitionReplaceMergeJson =
        "[\"xAxis\",\"yAxis\",\"legend\",\"polar\",\"angleAxis\",\"radiusAxis\",\"radar\",\"parallel\",\"parallelAxis\",\"visualMap\",\"grid\"]";

    private bool IsPhantomActive =>
        ShouldShowSkeleton && SkeletonStyle == ChartSkeletonStyle.Phantom && ShowLoadingSkeleton;

    /// <summary>Returns the JSON that actually goes to ECharts. Phantom mode uses
    /// the current cycling tick so each frame redistributes the random data, and
    /// mirrors the real chart's structure (category count, series count, stacking)
    /// via <see cref="ChartPlaceholderFactory.InferShape"/>.</summary>
    private string GetEffectiveJson()
    {
        if (IsPhantomActive)
        {
            var shape = PhantomShapeOverride ?? ChartPlaceholderFactory.InferShape(Option);
            return ChartPlaceholderFactory.CreateJson(SkeletonKind, _phantomTick, shape);
        }
        return GetOptionsJson();
    }

    // Fingerprint of the inputs that feed initChart (option JSON + theme + source).
    // Captured every time we attempt init so OnParametersSet can tell whether a change
    // AFTER a failure is meaningful enough to warrant a retry. Null until the first
    // init attempt runs.
    private string? _lastInitInputs;
    // Set by OnParametersSet when an init-relevant parameter changes while _initError is
    // latched. The error branch removed the host div, so we must re-render the host FIRST
    // (clear _initError) and re-attempt init on the following OnAfterRenderAsync pass.
    private bool _retryInit;

    private string InitInputsFingerprint() => $"{GetEffectiveJson()}{Theme}{EChartsSource}";

    protected override void OnParametersSet()
    {
        // Rebuild the screen-reader table from the real (non-phantom) option. Cheap
        // JSON parse; only runs when parameters change, not on the phantom render loop.
        _a11yTable = AccessibilityLayer ? BuildAccessibilityTable() : null;

        // Recovery after an init failure: the error branch tore down the #_chartId host
        // and left _initialized=false, so neither OnAfterRenderAsync branch ever runs
        // again. When the consumer changes an init-relevant input (Option/OptionJson,
        // Theme, EChartsSource — e.g. swapping in a valid EChartsSource), clear the error
        // so the host re-renders, and arm a retry that re-runs init on the next pass.
        if (_initError is not null && !_initialized && _lastInitInputs is not null
            && InitInputsFingerprint() != _lastInitInputs)
        {
            _initError = null;
            _retryInit = true;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender || _retryInit)
        {
            // _retryInit re-enters this path after a recoverable init failure: the host
            // div was just re-rendered (OnParametersSet cleared _initError) so the element
            // exists again and we can re-attempt initChart against it.
            _retryInit = false;
            _module ??= await Interop.ImportModuleAsync("./_content/Lumeo.Charts/js/echarts-interop.js");

            var json = GetEffectiveJson();
            _lastJson = json;
            _lastShape = ChartShape.From(json);
            _lastTheme = Theme;
            _lastGroup = Group;
            _lastInitInputs = InitInputsFingerprint();

            try
            {
                await _module.InvokeVoidAsync("initChart", _chartId, json, Theme, EChartsSource);
            }
            catch (JSException ex)
            {
                _initError = $"Chart initialization failed: {ex.Message}";
                Console.Error.WriteLine($"[Lumeo Chart] Init failed: {ex.Message}");
                if (OnInitError.HasDelegate)
                    await OnInitError.InvokeAsync(ex.Message);
                StateHasChanged();
                return;
            }
            _initialized = true;

            await RegisterChartEventsAsync();

            if (ShowLoading)
            {
                _lastShowLoading = true;
                await _module.InvokeVoidAsync("showLoading", _chartId, null);
            }

            // Capture the phantom state that was actually passed to ECharts. Must be
            // the value at init time (before any subsequent state change), so we can
            // correctly decide notMerge on the next update.
            _lastWasPhantom = IsPhantomActive;
            UpdatePhantomTimer();
            StateHasChanged();
        }
        else if (_initialized)
        {
            UpdatePhantomTimer();

            var json = GetEffectiveJson();
            var isPhantom = IsPhantomActive;
            if (json != _lastJson)
            {
                _lastJson = json;
                var shape = ChartShape.From(json);
                // Phantom↔real transition: keep notMerge=false so SERIES values tween
                // (bars move from phantom heights to real heights — feels like data
                // loading, not a snap). Use replaceMerge to fully replace layout
                // components (axes, legend, radar, polar, parallel, visualMap) so the
                // muted skeleton-box styling doesn't bleed into the real chart.
                var phantomFlipped = _lastWasPhantom != isPhantom;
                // A structural shrink (fewer series, shorter data, or removed
                // markLine/markArea annotations) needs replaceMerge:["series",...] so the
                // dropped tail-end items don't survive ECharts' index-merge as ghosts.
                var shrank = shape.ShrankFrom(_lastShape);
                string? replaceMergeJson =
                    phantomFlipped ? PhantomTransitionReplaceMergeJson
                    : shrank ? SeriesShrinkReplaceMergeJson
                    : null;
                _lastShape = shape;
                await _module!.InvokeVoidAsync("updateChart", _chartId, json, false, replaceMergeJson);
            }
            _lastWasPhantom = isPhantom;

            // Event callbacks / <ChartTooltip> wired AFTER first render (a delegate or the
            // tooltip slot newly appears because the parent re-rendered) are otherwise never
            // registered — registration ran only on firstRender / theme-change. Re-run it
            // whenever something is still unregistered; RegisterChartEventsAsync is idempotent
            // (each name guarded by _registeredEvents, tooltip by _tooltipBridgeRegistered) so
            // already-bound handlers are not double-attached.
            if (HasUnregisteredEvents)
                await RegisterChartEventsAsync();

            if (ShowLoading != _lastShowLoading)
            {
                _lastShowLoading = ShowLoading;
                if (ShowLoading)
                    await _module!.InvokeVoidAsync("showLoading", _chartId, null);
                else
                    await _module!.InvokeVoidAsync("hideLoading", _chartId);
            }

            if (Theme != _lastTheme)
            {
                _lastTheme = Theme;
                await _module!.InvokeVoidAsync("disposeChart", _chartId);
                // The fresh JS instance has no event listeners — reset the tracking set so
                // RegisterChartEventsAsync re-attaches them onto the new chart. The tooltip
                // bridge lives on the disposed instance too, so clear its flag as well or
                // RegisterChartEventsAsync's `!_tooltipBridgeRegistered` gate would skip
                // re-registering registerTooltipSlot — killing the <ChartTooltip> portal.
                _registeredEvents.Clear();
                _tooltipBridgeRegistered = false;
                var currentJson = _lastJson ?? GetEffectiveJson();
                await _module!.InvokeVoidAsync("initChart", _chartId, currentJson, Theme, EChartsSource);
                await RegisterChartEventsAsync();
            }

            if (Group != _lastGroup)
            {
                _lastGroup = Group;
                if (!string.IsNullOrEmpty(Group))
                    // Switch (or first set): re-home this chart onto the new group. Because
                    // setChartGroup REASSIGNS chart.group, any previous group membership is
                    // overwritten — no lingering connection to the old group remains.
                    await _module!.InvokeVoidAsync("setChartGroup", _chartId, Group);
                else
                    // Clear: detach from the old group so the chart stops syncing cursor/zoom
                    // with its former siblings. connectCharts only ever assigns a group, so
                    // without this the chart stayed wired to its old group forever.
                    await _module!.InvokeVoidAsync("setChartGroup", _chartId, null);
            }
        }
    }

    private void UpdatePhantomTimer()
    {
        if (_disposed) return;
        var cycle = EffectivePhantomCycleMs;
        if (IsPhantomActive)
        {
            if (_phantomLoopTask is null || _activePhantomCycleMs != cycle)
            {
                StopPhantomLoop();
                _activePhantomCycleMs = cycle;
                _phantomCts = new CancellationTokenSource();
                var token = _phantomCts.Token;
                _phantomLoopTask = RunPhantomLoopAsync(cycle, token);
            }
        }
        else if (_phantomLoopTask is not null)
        {
            StopPhantomLoop();
            _activePhantomCycleMs = 0;
        }
    }

    private void StopPhantomLoop()
    {
        try { _phantomCts?.Cancel(); } catch (ObjectDisposedException) { }
        _phantomCts?.Dispose();
        _phantomCts = null;
        // Note: we deliberately do NOT await the loop task here to avoid blocking
        // OnAfterRenderAsync. DisposeAsync awaits any final loop task to ensure
        // no callback runs after dispose returns.
        _phantomLoopTask = null;
    }

    private async Task RunPhantomLoopAsync(int cycle, CancellationToken token)
    {
        // PeriodicTimer ticks on a fixed cadence; cancellation breaks the loop
        // immediately and lets DisposeAsync await completion deterministically.
        using var timer = new PeriodicTimer(TimeSpan.FromMilliseconds(cycle));
        try
        {
            while (await timer.WaitForNextTickAsync(token).ConfigureAwait(false))
            {
                if (_disposed || token.IsCancellationRequested) return;
                _phantomTick++;
                // Dispatch via SafeAsyncDispatcher so any outer-task fault (circuit
                // disposed mid-tick) is caught — InvokeAsync itself can throw
                // synchronously after dispose.
                SafeAsyncDispatcher.FireAndForget(
                    fn => InvokeAsync(fn),
                    async () =>
                    {
                        if (_disposed || token.IsCancellationRequested) return;
                        if (!_initialized || _module is null || !IsPhantomActive) return;
                        var shape = PhantomShapeOverride ?? ChartPlaceholderFactory.InferShape(Option);
                        var json = ChartPlaceholderFactory.CreateJson(SkeletonKind, _phantomTick, shape);
                        _lastJson = json;
                        try
                        {
                            await _module.InvokeVoidAsync("updateChart", _chartId, json, false);
                        }
                        catch (JSDisconnectedException) { }
                        catch (ObjectDisposedException) { }
                    },
                    "Lumeo.Chart.Phantom");
            }
        }
        catch (OperationCanceledException) { /* expected on Dispose */ }
    }

    // True when a wired-up event delegate or the <ChartTooltip> slot has NOT yet been
    // registered onto the live JS instance. Drives the post-first-render re-registration so
    // callbacks/tooltips added later (parent re-render) actually get bound. Already-bound
    // delegates contribute nothing (their name is in _registeredEvents).
    private bool HasUnregisteredEvents =>
        (OnClick.HasDelegate && !_registeredEvents.Contains("click"))
        || (OnMouseOver.HasDelegate && !_registeredEvents.Contains("mouseover"))
        || (OnDoubleClick.HasDelegate && !_registeredEvents.Contains("dblclick"))
        || (OnBrushSelected.HasDelegate && !_registeredEvents.Contains("brushSelected"))
        || (OnDataZoom.HasDelegate && !_registeredEvents.Contains("dataZoom"))
        || (_tooltipRegistration.Current is not null && !_tooltipBridgeRegistered);

    private async Task RegisterChartEventsAsync()
    {
        if (_module is null || !_initialized) return;

        if (OnClick.HasDelegate || OnMouseOver.HasDelegate || OnDoubleClick.HasDelegate || OnBrushSelected.HasDelegate || OnDataZoom.HasDelegate)
        {
            _selfRef ??= DotNetObjectReference.Create(this);
            // _registeredEvents guards each name so a re-run (delegate wired after first
            // render) only attaches the newly-added events, never double-binding ones the
            // live JS instance already has.
            if (OnClick.HasDelegate && _registeredEvents.Add("click"))
                await _module.InvokeVoidAsync("registerChartEvent", _chartId, "click", _selfRef);
            if (OnMouseOver.HasDelegate && _registeredEvents.Add("mouseover"))
                await _module.InvokeVoidAsync("registerChartEvent", _chartId, "mouseover", _selfRef);
            if (OnDoubleClick.HasDelegate && _registeredEvents.Add("dblclick"))
                await _module.InvokeVoidAsync("registerChartEvent", _chartId, "dblclick", _selfRef);
            if (OnBrushSelected.HasDelegate && _registeredEvents.Add("brushSelected"))
                await _module.InvokeVoidAsync("registerChartEvent", _chartId, "brushSelected", _selfRef);
            if (OnDataZoom.HasDelegate && _registeredEvents.Add("dataZoom"))
                await _module.InvokeVoidAsync("registerChartEvent", _chartId, "dataZoom", _selfRef);
        }

        // Register the tooltip-portal bridge once a ChartTooltip slot exists. The JS
        // side installs a tooltip.formatter that calls OnTooltipPointChange (updating
        // _tooltipContext + rendering the portal) and returns portal.innerHTML to
        // ECharts each frame.
        if (_tooltipRegistration.Current is not null && !_tooltipBridgeRegistered)
        {
            _selfRef ??= DotNetObjectReference.Create(this);
            try
            {
                await _module.InvokeVoidAsync("registerTooltipSlot", _chartId, _tooltipPortalId, _selfRef);
                _tooltipBridgeRegistered = true;
            }
            catch (Microsoft.JSInterop.JSException)
            {
                // Older Lumeo.Charts JS bundles without registerTooltipSlot fall through —
                // ECharts uses its default tooltip body and the Razor portal stays unused.
            }
        }

        if (!string.IsNullOrEmpty(Group))
            await _module.InvokeVoidAsync("connectCharts", Group, new[] { _chartId });
    }

    private string GetOptionsJson()
    {
        string baseJson;
        if (!string.IsNullOrEmpty(OptionJson)) baseJson = OptionJson;
        else
        {
            try { baseJson = Option?.ToJson() ?? "{}"; }
            catch (Exception ex)
            {
                Console.Error.WriteLine($"[Lumeo Chart] Serialization failed: {ex.Message}");
                baseJson = "{}";
            }
        }
        return MergeAnnotations(baseJson);
    }

    // Merge cascaded <ChartThreshold> / <ChartReferenceZone> registrations into
    // series[0].markLine.data / markArea.data on the already-serialized JSON. Operating
    // on JsonNode lets us avoid mutating the consumer's EChartOption — and survives the
    // pre-serialized OptionJson path the same way. No-op when there are no registrations
    // or no series to attach to (e.g. an empty placeholder option).
    private string MergeAnnotations(string baseJson)
        => ChartAnnotationMerger.Merge(baseJson, _annotations.Thresholds, _annotations.Zones);

    // Projects the REAL merged option (not the phantom placeholder) into the SR table.
    // Uses GetOptionsJson so the OptionJson and typed-Option paths are handled uniformly.
    private ChartAccessibility.ChartDataTable? BuildAccessibilityTable()
        => ChartAccessibility.Build(GetOptionsJson(), MaxAccessibilityRows);

    [JSInvokable]
    public async Task OnChartEvent(string eventName, string dataJson)
    {
        var args = System.Text.Json.JsonSerializer.Deserialize<ChartEventArgs>(dataJson) ?? new();
        if (eventName == "click") await OnClick.InvokeAsync(args);
        else if (eventName == "mouseover") await OnMouseOver.InvokeAsync(args);
        else if (eventName == "dblclick") await OnDoubleClick.InvokeAsync(args);
        else if (eventName == "brushSelected") await OnBrushSelected.InvokeAsync(args);
        else if (eventName == "dataZoom") await OnDataZoom.InvokeAsync(args);
    }

    /// <summary>
    /// Invoked from the JS-side tooltip formatter each time ECharts is about to render
    /// the tooltip for a new point. We deserialize the formatter <c>params</c> object,
    /// project it into a <see cref="ChartTooltipContext"/>, and re-render so the hidden
    /// portal updates. The next animation frame the formatter reads the fresh innerHTML.
    /// </summary>
    [JSInvokable]
    public Task OnTooltipPointChange(string paramsJson)
    {
        try
        {
            var raw = System.Text.Json.JsonSerializer.Deserialize<Dictionary<string, System.Text.Json.JsonElement>>(paramsJson)
                ?? new();

            string Get(string key) => raw.TryGetValue(key, out var v) && v.ValueKind == System.Text.Json.JsonValueKind.String
                ? v.GetString() ?? "" : "";

            int GetInt(string key) => raw.TryGetValue(key, out var v) && v.ValueKind == System.Text.Json.JsonValueKind.Number
                ? v.GetInt32() : 0;

            double? GetValue()
            {
                if (!raw.TryGetValue("value", out var v)) return null;
                if (v.ValueKind == System.Text.Json.JsonValueKind.Number) return v.GetDouble();
                if (v.ValueKind == System.Text.Json.JsonValueKind.Array && v.GetArrayLength() > 0)
                {
                    // Multi-dim point (scatter / candlestick) — first dimension is the headline.
                    var first = v[0];
                    if (first.ValueKind == System.Text.Json.JsonValueKind.Number) return first.GetDouble();
                }
                return null;
            }

            var boxed = raw.ToDictionary(kv => kv.Key, kv => (object?)kv.Value);

            // points: forwarded by the JS bridge as a flat array of per-series snapshots.
            // For axis-trigger tooltips this contains every series at the hovered x; for
            // item-trigger it'll be a single-entry list mirroring the headline fields.
            var points = ProjectPoints(raw);

            _tooltipContext = new ChartTooltipContext(
                SeriesName: Get("seriesName"),
                SeriesType: Get("seriesType"),
                SeriesIndex: GetInt("seriesIndex"),
                DataName: Get("name"),
                DataIndex: GetInt("dataIndex"),
                Value: GetValue(),
                Color: raw.TryGetValue("color", out var c) && c.ValueKind == System.Text.Json.JsonValueKind.String ? c.GetString() : null,
                Raw: boxed)
            {
                Points = points,
            };
            return InvokeAsync(StateHasChanged);
        }
        catch
        {
            // Malformed payload from JS — don't break the chart. Leave the last good
            // context in place so the tooltip keeps rendering its previous content.
            return Task.CompletedTask;
        }
    }

    // Extracts the per-series snapshots from the bridge's "points" array. We only need
    // a handful of fields; everything else stays in Raw on the headline. Defensive on
    // shape — a missing / non-array "points" payload yields an empty list, and malformed
    // (non-object) entries are skipped. Consumers fall back to the typed headline fields
    // when Points is empty.
    private static IReadOnlyList<ChartTooltipPoint> ProjectPoints(
        Dictionary<string, System.Text.Json.JsonElement> raw)
    {
        if (!raw.TryGetValue("points", out var pts) || pts.ValueKind != System.Text.Json.JsonValueKind.Array)
            return Array.Empty<ChartTooltipPoint>();

        var result = new List<ChartTooltipPoint>(pts.GetArrayLength());
        foreach (var p in pts.EnumerateArray())
        {
            if (p.ValueKind != System.Text.Json.JsonValueKind.Object) continue;

            string Str(string key) => p.TryGetProperty(key, out var v) && v.ValueKind == System.Text.Json.JsonValueKind.String
                ? v.GetString() ?? "" : "";
            int Int(string key) => p.TryGetProperty(key, out var v) && v.ValueKind == System.Text.Json.JsonValueKind.Number
                ? v.GetInt32() : 0;
            string? StrOrNull(string key) => p.TryGetProperty(key, out var v) && v.ValueKind == System.Text.Json.JsonValueKind.String
                ? v.GetString() : null;
            double? Val()
            {
                if (!p.TryGetProperty("value", out var v)) return null;
                if (v.ValueKind == System.Text.Json.JsonValueKind.Number) return v.GetDouble();
                if (v.ValueKind == System.Text.Json.JsonValueKind.Array && v.GetArrayLength() > 0
                    && v[0].ValueKind == System.Text.Json.JsonValueKind.Number)
                    return v[0].GetDouble();
                return null;
            }

            result.Add(new ChartTooltipPoint(
                SeriesName: Str("seriesName"),
                SeriesType: Str("seriesType"),
                SeriesIndex: Int("seriesIndex"),
                DataIndex: Int("dataIndex"),
                Value: Val(),
                Color: StrOrNull("color"),
                Marker: StrOrNull("marker")));
        }
        return result;
    }

    public async Task<string?> GetImageAsync(string type = "png", int pixelRatio = 2)
    {
        if (_module is null || !_initialized) return null;
        return await _module.InvokeAsync<string?>("getDataURL", _chartId,
            new { type, pixelRatio, backgroundColor = "#fff" });
    }

    public async Task AppendDataAsync(int seriesIndex, string dataJson)
    {
        if (_module is null || !_initialized) return;
        await _module.InvokeVoidAsync("appendData", _chartId, seriesIndex, dataJson);
    }

    public async Task DispatchActionAsync(string actionJson)
    {
        if (_module is null || !_initialized) return;
        await _module.InvokeVoidAsync("dispatchAction", _chartId, actionJson);
    }

    public async Task ResizeAsync()
    {
        if (_module is null || !_initialized) return;
        await _module.InvokeVoidAsync("resizeChart", _chartId);
    }

    public async ValueTask DisposeAsync()
    {
        // Set the disposed flag BEFORE any await so the loop's flag check can
        // short-circuit even if Dispose runs concurrently with a tick.
        _disposed = true;

        // Cancel and await the phantom loop so no callback can run after this
        // method returns — Timer.Dispose() did NOT give us this guarantee.
        try { _phantomCts?.Cancel(); } catch (ObjectDisposedException) { }
        var loop = _phantomLoopTask;
        _phantomLoopTask = null;
        if (loop is not null)
        {
            try { await loop.ConfigureAwait(false); }
            catch (OperationCanceledException) { /* covers TaskCanceledException too */ }
        }
        _phantomCts?.Dispose();
        _phantomCts = null;

        if (_module is not null && _initialized)
        {
            try
            {
                await _module.InvokeVoidAsync("disposeChart", _chartId);
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        _selfRef?.Dispose();
    }

    public class ChartEventArgs
    {
        public string Name { get; set; } = "";
        public string SeriesName { get; set; } = "";
        public int SeriesIndex { get; set; } = -1;
        public int DataIndex { get; set; } = -1;
        public string Value { get; set; } = "";
        public string ComponentType { get; set; } = "";
    }

    // Structural fingerprint of an option JSON used to detect a "shrink" between two
    // consecutive updates. ECharts' setOption(notMerge:false) merges component arrays by
    // index, so a GROWN or same-shape option merges cleanly, but a SHRUNK one (fewer
    // series, shorter series data, or fewer markLine/markArea annotation entries) would
    // leave the removed tail-end items behind as ghosts unless we replaceMerge them.
    private readonly struct ChartShape
    {
        public static readonly ChartShape Empty = new(Array.Empty<int>(), Array.Empty<int>(), Array.Empty<int>());

        // Per-series data-point counts, markLine entry counts, and markArea entry counts.
        // Length of each array == series count, so a series removal shows as a shorter array.
        private readonly int[] _dataLen;
        private readonly int[] _markLineLen;
        private readonly int[] _markAreaLen;

        private ChartShape(int[] dataLen, int[] markLineLen, int[] markAreaLen)
        {
            _dataLen = dataLen;
            _markLineLen = markLineLen;
            _markAreaLen = markAreaLen;
        }

        public int SeriesCount => _dataLen.Length;

        /// <summary>Parses the option JSON into a shape. Malformed / series-less JSON
        /// yields <see cref="Empty"/>, which never reports a shrink (so a transient empty
        /// option doesn't force a destructive replaceMerge).</summary>
        public static ChartShape From(string? json)
        {
            if (string.IsNullOrEmpty(json)) return Empty;
            try
            {
                if (System.Text.Json.Nodes.JsonNode.Parse(json) is not System.Text.Json.Nodes.JsonObject obj)
                    return Empty;
                if (obj["series"] is not System.Text.Json.Nodes.JsonArray series || series.Count == 0)
                    return Empty;

                var dataLen = new int[series.Count];
                var markLineLen = new int[series.Count];
                var markAreaLen = new int[series.Count];
                for (var i = 0; i < series.Count; i++)
                {
                    if (series[i] is not System.Text.Json.Nodes.JsonObject s) continue;
                    dataLen[i] = (s["data"] as System.Text.Json.Nodes.JsonArray)?.Count ?? 0;
                    markLineLen[i] = ((s["markLine"] as System.Text.Json.Nodes.JsonObject)?["data"]
                        as System.Text.Json.Nodes.JsonArray)?.Count ?? 0;
                    markAreaLen[i] = ((s["markArea"] as System.Text.Json.Nodes.JsonObject)?["data"]
                        as System.Text.Json.Nodes.JsonArray)?.Count ?? 0;
                }
                return new ChartShape(dataLen, markLineLen, markAreaLen);
            }
            catch
            {
                return Empty;
            }
        }

        /// <summary>True when THIS shape has fewer structural elements than
        /// <paramref name="prev"/> — fewer series, or a series whose data /
        /// markLine / markArea entry count dropped. A grown or unchanged shape returns
        /// false (the default index-merge handles those without ghosts).</summary>
        public bool ShrankFrom(ChartShape prev)
        {
            if (prev.SeriesCount == 0) return false; // nothing to shrink from
            if (SeriesCount < prev.SeriesCount) return true;
            // Compare overlapping series; a per-series data/annotation removal also leaves
            // ghosts under index-merge.
            var common = Math.Min(SeriesCount, prev.SeriesCount);
            for (var i = 0; i < common; i++)
            {
                if (_dataLen[i] < prev._dataLen[i]) return true;
                if (_markLineLen[i] < prev._markLineLen[i]) return true;
                if (_markAreaLen[i] < prev._markAreaLen[i]) return true;
            }
            return false;
        }
    }
}

using System.Globalization;
using System.Linq;
using System.Text.Json.Nodes;

namespace Lumeo;

/// <summary>
/// Builds a screen-reader-friendly data model from an ECharts option so the
/// canvas-rendered <see cref="Chart"/> can expose an accessible fallback — the
/// equivalent of shadcn/ui's <c>accessibilityLayer</c> for Recharts.
/// <para>
/// ECharts offers a native <c>aria.enabled</c> flag that emits a single verbose
/// <c>aria-label</c> string once the chart has initialised in JS. We deliberately
/// render our own visually-hidden <c>&lt;table&gt;</c> from the SAME series data
/// instead, because a real table is (a) navigable cell-by-cell by assistive tech
/// (row/column semantics, not one long sentence), (b) present in the DOM
/// server-side / pre-render before any JS runs, and (c) deterministic and unit
/// testable. The generated <see cref="ChartDataTable.Summary"/> doubles as the
/// focusable host's <c>aria-label</c>.
/// </para>
/// </summary>
public static class ChartAccessibility
{
    /// <summary>
    /// Default upper bound on the number of data rows the screen-reader table
    /// materialises. A big series (thousands of points) would otherwise emit one
    /// hidden <c>&lt;tr&gt;</c> per point — heavy DOM bloat that helps no assistive
    /// tech (a SR user cannot meaningfully tab through 5000 rows). Above the cap the
    /// table keeps the first <see cref="DefaultMaxAccessibilityRows"/> rows plus a
    /// single "… and N more data points" summary row; the caption / aria-label
    /// summary is computed from the FULL data so its totals stay accurate.
    /// </summary>
    public const int DefaultMaxAccessibilityRows = 50;

    /// <summary>A screen-reader data table projected from an ECharts option.</summary>
    /// <param name="Summary">One-line description used as the chart's <c>aria-label</c>.</param>
    /// <param name="ColumnHeaders">Header cells for the table's <c>&lt;thead&gt;</c>.
    /// The first entry labels the row-header column.</param>
    /// <param name="Rows">One row per category (cartesian) or data point, capped at
    /// the requested row limit.</param>
    /// <param name="TruncationNote">Non-null when <see cref="Rows"/> was capped: a
    /// human-readable "… and N more data points" note the host renders as a final
    /// spanning row. Null when the full data fit under the cap.</param>
    public sealed record ChartDataTable(
        string Summary,
        IReadOnlyList<string> ColumnHeaders,
        IReadOnlyList<ChartDataRow> Rows,
        string? TruncationNote = null);

    /// <summary>A single table row: a row-header cell plus its value cells.</summary>
    public sealed record ChartDataRow(string Header, IReadOnlyList<string> Cells);

    /// <summary>
    /// Projects the given ECharts option JSON into a <see cref="ChartDataTable"/>,
    /// or <c>null</c> when the option carries no usable series data (in which case
    /// the chart renders no accessibility table). Never throws — malformed JSON
    /// yields <c>null</c>.
    /// </summary>
    /// <param name="optionJson">The ECharts option JSON.</param>
    /// <param name="maxRows">Upper bound on materialised data rows (default
    /// <see cref="DefaultMaxAccessibilityRows"/>). <c>0</c> or negative means
    /// unlimited. When the projected data exceeds the cap the table keeps the first
    /// <paramref name="maxRows"/> rows and sets
    /// <see cref="ChartDataTable.TruncationNote"/>; the caption/summary totals are
    /// always computed from the complete data, so they remain accurate.</param>
    public static ChartDataTable? Build(string? optionJson, int maxRows = DefaultMaxAccessibilityRows)
    {
        if (string.IsNullOrWhiteSpace(optionJson))
            return null;

        JsonNode? root;
        try { root = JsonNode.Parse(optionJson); }
        catch { return null; }

        if (root is not JsonObject obj)
            return null;

        var series = ReadSeries(obj);
        if (series.Count == 0)
            return null;

        var categories = ReadCategories(obj);
        var typeLabel = ChartTypeLabel(series[0].Type);

        var table = categories.Count > 0
            ? BuildCartesian(typeLabel, categories, series)
            : BuildCategorical(typeLabel, series);

        return CapRows(table, maxRows);
    }

    // Caps the row list so a huge series doesn't emit thousands of hidden <tr>s.
    // The Summary was built from the FULL data (category / point counts), so it is
    // untouched — only the materialised Rows shrink, with the overflow announced by
    // a single TruncationNote row. maxRows <= 0 disables the cap entirely.
    private static ChartDataTable CapRows(ChartDataTable table, int maxRows)
    {
        if (maxRows <= 0 || table.Rows.Count <= maxRows)
            return table;

        var omitted = table.Rows.Count - maxRows;
        var kept = table.Rows.Take(maxRows).ToList();
        var note = $"… and {omitted} more data point{(omitted == 1 ? "" : "s")}";
        return table with { Rows = kept, TruncationNote = note };
    }

    private readonly record struct SeriesInfo(string Name, string? Type, IReadOnlyList<JsonNode?> Data);

    private static List<SeriesInfo> ReadSeries(JsonObject obj)
    {
        var result = new List<SeriesInfo>();

        // ECharts accepts "series" as EITHER an array OR a single object
        // ("series": { "type": "pie", "data": [...] }). Treat the object form as a
        // one-element sequence so the SR table + caption are built for it too —
        // previously the object shape yielded nothing and the a11y layer silently
        // vanished (round-9 finding).
        IEnumerable<JsonNode?> nodes = obj["series"] switch
        {
            JsonArray arr => arr,
            JsonObject single => new JsonNode?[] { single },
            _ => Array.Empty<JsonNode?>(),
        };

        var index = 0;
        foreach (var node in nodes)
        {
            index++;
            if (node is not JsonObject s)
                continue;
            var name = (s["name"] as JsonValue)?.ToString();
            var type = (s["type"] as JsonValue)?.ToString();
            var data = s["data"] as JsonArray;
            result.Add(new SeriesInfo(
                string.IsNullOrEmpty(name) ? $"Series {index}" : name!,
                type,
                data?.ToList() ?? new List<JsonNode?>()));
        }
        return result;
    }

    // Category labels come from the first cartesian axis (x then y) that carries a
    // "data" string array — covers both vertical (xAxis) and horizontal (yAxis) bars.
    private static List<string> ReadCategories(JsonObject obj)
    {
        foreach (var key in new[] { "xAxis", "yAxis" })
        {
            var data = obj[key] switch
            {
                JsonArray arr => (arr.FirstOrDefault() as JsonObject)?["data"] as JsonArray,
                JsonObject axis => axis["data"] as JsonArray,
                _ => null,
            };
            if (data is { Count: > 0 })
                return data.Select(FormatValue).ToList();
        }
        return new List<string>();
    }

    private static ChartDataTable BuildCartesian(
        string typeLabel, List<string> categories, List<SeriesInfo> series)
    {
        var headers = new List<string> { "Category" };
        headers.AddRange(series.Select(s => s.Name));

        var rows = new List<ChartDataRow>(categories.Count);
        for (var c = 0; c < categories.Count; c++)
        {
            var cells = new List<string>(series.Count);
            foreach (var s in series)
                cells.Add(c < s.Data.Count ? FormatValue(s.Data[c]) : "");
            rows.Add(new ChartDataRow(categories[c], cells));
        }

        var names = string.Join(", ", series.Select(s => s.Name));
        var summary = series.Count == 1
            ? $"{typeLabel} with {categories.Count} categories: {names}."
            : $"{typeLabel} with {series.Count} series ({names}) across {categories.Count} categories.";
        return new ChartDataTable(summary, headers, rows);
    }

    // No cartesian axis (pie / funnel / radar / scatter …). One series → Name/Value
    // rows; several → Series/Item/Value long form so every point is still reachable.
    private static ChartDataTable BuildCategorical(string typeLabel, List<SeriesInfo> series)
    {
        int points = series.Sum(s => s.Data.Count);

        if (series.Count == 1)
        {
            var single = series[0];
            var headers = new List<string> { "Name", "Value" };
            var rows = new List<ChartDataRow>(single.Data.Count);
            var i = 0;
            foreach (var item in single.Data)
            {
                i++;
                rows.Add(new ChartDataRow(ItemName(item, i), new[] { ItemValue(item) }));
            }
            return new ChartDataTable(
                $"{typeLabel} with {single.Data.Count} data points.", headers, rows);
        }

        var multiHeaders = new List<string> { "Series", "Item", "Value" };
        var multiRows = new List<ChartDataRow>();
        foreach (var s in series)
        {
            var i = 0;
            foreach (var item in s.Data)
            {
                i++;
                multiRows.Add(new ChartDataRow(s.Name, new[] { ItemName(item, i), ItemValue(item) }));
            }
        }
        var names = string.Join(", ", series.Select(s => s.Name));
        return new ChartDataTable(
            $"{typeLabel} with {series.Count} series ({names}) and {points} data points.",
            multiHeaders, multiRows);
    }

    private static string ItemName(JsonNode? item, int ordinal) =>
        item is JsonObject o && o["name"] is JsonValue n && !string.IsNullOrEmpty(n.ToString())
            ? n.ToString()
            : ordinal.ToString(CultureInfo.InvariantCulture);

    private static string ItemValue(JsonNode? item) =>
        item is JsonObject o && o["value"] is { } v ? FormatValue(v) : FormatValue(item);

    private static string FormatValue(JsonNode? node)
    {
        switch (node)
        {
            case null:
                return "";
            case JsonArray arr:
                return string.Join(", ", arr.Select(FormatValue));
            case JsonObject o:
                if (o["value"] is { } v) return FormatValue(v);
                if (o["name"] is { } n) return n.ToString();
                return "";
            case JsonValue val:
                if (val.TryGetValue<double>(out var d))
                    return d.ToString(CultureInfo.InvariantCulture);
                if (val.TryGetValue<bool>(out var b))
                    return b ? "true" : "false";
                return val.ToString();
            default:
                return node.ToString();
        }
    }

    private static string ChartTypeLabel(string? type) => (type?.ToLowerInvariant()) switch
    {
        "bar" => "Bar chart",
        "line" => "Line chart",
        "pie" => "Pie chart",
        "scatter" or "effectscatter" => "Scatter chart",
        "radar" => "Radar chart",
        "candlestick" => "Candlestick chart",
        "heatmap" => "Heatmap",
        "funnel" => "Funnel chart",
        "gauge" => "Gauge chart",
        "sankey" => "Sankey diagram",
        "treemap" => "Treemap",
        "sunburst" => "Sunburst chart",
        "boxplot" => "Box plot",
        "graph" => "Graph",
        "tree" => "Tree diagram",
        _ => "Chart",
    };
}

